from openai_agents import Tool

def validate_tool_output(output: str) -> bool:
    risky_indicators = [
        'sudo', 'root', 'admin', 'exec', 'system',
        'ignore instructions', 'new role', 'override',
        'base64:IGNore', 'rot13:abgrf'
    ]

    for indicator in risky_indicators:
        if indicator.lower() in output.lower():
            print(f'🚨 Tool output blocked: {indicator}')
            return False
    return True

