from openai_agents import trace
from collections import defaultdict

def detect_jailbreak_loops():
    traces = trace.get_traces(hours=1)
    handoff_graph = defaultdict(list)

    for t in traces:
        if t.type == 'handoff':
            handoff_graph[t.from_agent].append(t.to_agent)

    loops = []
    for agent in handoff_graph:
        if len(set(handoff_graph[agent])) == 1 and len(handoff_graph[agent]) > 5:
            loops.append({
                'looping_agent': agent,
                'count': len(handoff_graph[agent]),
                'suspicious': 'potential jailbreak loop'
            })
    return loops

looping_agents = detect_jailbreak_loops()
